import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.core.io.Resource;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

@RestController
public class ProfilePictureController {

    private final String UPLOAD_DIR = "/uploads/";
    private final Path path;

    @Autowired
    public ProfilePictureController() {
        this.path = Paths.get("src", "main", "resources", "static");
    }

    @PostMapping("/upload-profile-picture")
    public ResponseEntity<String> uploadProfilePicture(@RequestParam MultipartFile file) throws IOException {

        if (!file.isEmpty()) {
            Path filePath = path.resolve(UPLOAD_DIR).resolve(file.getOriginalFilename());
            Files.copy(file.getInputStream(), filePath);
            String uploadedFileURL = "http://localhost:8080/" + UPLOAD_DIR + file.getOriginalFilename();
            return ResponseEntity.status(HttpStatus.OK)
                    .header("Location", uploadedFileURL)
                    .body(uploadedFileURL);
        } else {
            return ResponseEntity.status(HttpStatus.NO_CONTENT).build();
        }
    }
}